```bash
applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Utils/LoopUtils.cpp
@@
 void llvm::appendReversedLoopsToWorklist(
     RangeT &&Loops, SmallPriorityWorklist<Loop *, 4> &Worklist) {
-  // We append loops to the worklist in reverse order because loops
-  // may get deleted. If a loop gets deleted and there are still loops
-  // to process, these loops have to be valid and not deleted.
-  for (Loop *L : Loops) {
-    Worklist.insert(Worklist.begin(), L);
-    for (Loop *SubLoop : reverse(L->getSubLoops()))
-      Worklist.insert(Worklist.begin(), SubLoop);
-  }
+  // We append loops to the worklist in reverse order because loops may get
+  // deleted. If a loop gets deleted and there are still loops to process,
+  // these loops have to be valid and not deleted.
+  //
+  // Some transformations may invalidate loops eagerly; guard against accessing
+  // subloops of an invalid loop by checking isInvalid() before touching it.
+  for (Loop *L : Loops) {
+    if (!L || L->isInvalid())
+      continue;
+    Worklist.insert(Worklist.begin(), L);
+    // Only traverse subloops if the parent loop is still valid.
+    const auto &Subs = L->getSubLoops();
+    for (Loop *SubLoop : reverse(Subs)) {
+      if (!SubLoop || SubLoop->isInvalid())
+        continue;
+      Worklist.insert(Worklist.begin(), SubLoop);
+    }
+  }
 }
*** End Patch
EOF
&& submit-patch
```

